CREATE TABLE system_to_data_type
(
	id serial,
	system_id integer NOT NULL,
	data_type_id integer DEFAULT NULL,
	CONSTRAINT pk_system_to_data_type PRIMARY KEY (id)
	, CONSTRAINT fk_system_to_data_type_to_system FOREIGN KEY (system_id) REFERENCES systems (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
	, CONSTRAINT fk_system_to_data_type_to_data_type FOREIGN KEY (data_type_id) REFERENCES data_type_classifications (id) MATCH SIMPLE ON UPDATE NO ACTION ON DELETE NO ACTION
);
CREATE INDEX i_system_to_data_type_system ON system_to_data_type (system_id);
CREATE INDEX i_system_to_data_type_data_type ON system_to_data_type (data_type_id);
